#include <sstream>
#include <streambuf>

// Declare the user's main function, which is renamed to user_main for testing.
extern int user_main();

// Function to run a single test case
std::string run_test_case(const std::string& input_str) {
    std::stringstream ss_in(input_str);
    std::stringstream ss_out;

    // Save original cin/cout buffers
    std::streambuf* old_cin_buf = std::cin.rdbuf();
    std::streambuf* old_cout_buf = std::cout.rdbuf();

    // Redirect cin/cout
    std::cin.rdbuf(ss_in.rdbuf());
    std::cout.rdbuf(ss_out.rdbuf());

    // Call the user's program logic
    user_main();

    // Restore original cin/cout buffers
    std::cin.rdbuf(old_cin_buf);
    std::cout.rdbuf(old_cout_buf);

    return ss_out.str();
}

int main() {
    std::vector<std::pair<std::string, std::string>> test_cases = {
        {"hello", "Enter a string: olleh\n"},
        {"world", "Enter a string: dlrow\n"},
        {"", "Enter a string: \n"},
        {"a", "Enter a string: a\n"},
        {"123 456", "Enter a string: 321\n"},
        {"Racecar", "Enter a string: racecaR\n"}
    };

    for (size_t i = 0; i < test_cases.size(); ++i) {
        const auto& tc = test_cases[i];
        std::string actual_output = run_test_case(tc.first);
        if (actual_output == tc.second) {
            // Test passed logic (e.g., print success message)
        } else {
            // Test failed logic (e.g., print error message, expected vs actual)
        }
    }

    return 0;
}
